head.script:
//==================================================================================================================
// id       : fi_203_01_07b
// 이름     : 총계정원장조회
// 경로     : 회계/재무회계/일반회계/원장관리/
// 작 성 자 : 오영재
// 작 업 일 : 2025-12-24
//            2026-04-24 김용욱 : 1년 이상 조회 금지 추가 / 증빙개수 blue / 팝업 정리 외
// 사용계정 : 내부
// 비고     :
//            돋보기 전체 조회 : 계정,부서,사업영역
//
// 업로드   :
// 다운로드 : 
// 레포트   :
// 호출     : 
//==================================================================================================================

scwin.load = true;  // 초기실행 여부

scwin.today = $c.date.getServerDateTime("yyyyMMdd");
scwin.vLoginCoCd = $c.gus.cfIsNull($c.data.getMemInfo("coCd")) ? '' : $c.data.getMemInfo("coCd"); // 소속 자회사  
scwin.vLoginCoClsCd = $c.gus.cfIsNull($c.data.getMemInfo("coClsCd")) ? '' : $c.data.getMemInfo("coClsCd");
scwin.vUserHomeClsCd = $c.gus.cfIsNull($c.data.getMemInfo("userHomeClsCd")) ? '' : $c.data.getMemInfo("userHomeClsCd");
scwin.vUserId = $c.gus.cfIsNull($c.data.getMemInfo("userId")) ? '' : $c.data.getMemInfo("userId");
scwin.privAdmin = $c.gus.cfIsNull($c.data.getMemInfo("privAdmin")) ? '' : $c.data.getMemInfo("privAdmin");

scwin.isSubCompany = false;

scwin.quantiDtyOfRows = "30000";
scwin.pageNumber = "1";
//hidden
scwin.txtCoClsCd = "";
scwin.hd_acctCdGbn = "";
scwin.hd_acctDeptCdGbn = "";
scwin.txt_pageNumber = "";
scwin.txt_quantityOfRows = "";

scwin.onpageload = function () {
    console.log("====== onpageload ==================v 1.01");

    const codeOptions = [
        { grpCd: "FI008", compID: "lc_postYn" }
    ];

    // console.log(" codeOptions : "+ JSON.stringify(codeOptions));
    $c.data.setCommonCode(codeOptions);
};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
    console.log("  ==--== onUdcCompleted");

    // 2025-10-14 : 작성일자 포커스 위치 이동
    $p.setTimeout(function () {
        scwin.f_Setting();
        scwin.f_setCompanyInfo();
        lc_postYn.setSelectedIndex(1);

        // paging 처리 관련
        $c.gus.cfDisableObjects([btn_addSearch]);
        btn_addSearch.hide();
        bSearch.hide();
        lAddRow.hide();
        bSearch2.hide();

        scwin.getQuantityOfRows();
        scwin.f_empNo();
    }, { "delay": 50 });
};


//공통 코드 UDC 로드 후
scwin.ondataload = function () {
    // lc_postYn.index="1";
    lc_postYn.setValue(1);
};


// @@ ====== 준비 ============================================================================== //

//-------------------------------------------------------------------------
// 기본셋팅
//------------------------------------------------------------------------- 
scwin.f_Setting = function () {
    ed_qryYm.setValue(scwin.today.substring(0, 6));
    ed_qryYmEnd.setValue(scwin.today.substring(0, 6));

    ed_acctCdSt.options.hidVal = ds_search.get("acctCdSt");
    ed_acctDeptCd.options.hidVal = ds_search.get("acctDeptCd");

    lc_qryCond.setSelectedIndex(0);
    ed_qryYm.focus();
    scwin.f_QryCond();
};


//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function () {
    // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
    if (scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD) {
        scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
    }

    ed_coCd.setValue(scwin.vLoginCoCd);

    scwin.load = true;
    scwin.f_PopUpCompanyInfo('T');
};


//-------------------------------------------------------------------------
// FI616 (조회데이터Row설정) 조회
//-------------------------------------------------------------------------
scwin.getQuantityOfRows = function () {
    console.log("===== getQuantityOfRows - FI616 (조회데이터Row설정) 조회");

    let grp_cd = "FI616";  // 조회데이터Row설정 - 1000

    // SELECT 절 
    let param1 =
        " CD      as COL1 "
        + ",CD_NM 	as COL2 "
        + ",'' 		as COL3 "
        + ",'' 		as COL4 "
        + ",'' 		as COL5 "
        + ",'' 		as COL6 "
        + ",''      as COL7 "
        + ",''      as COL8 "
        + ",''      as COL9 "
        + ",''      as COL10"
        ;

    // 대상테이블 	
    let param2 =
        " TB_ZZ002 "
        ;

    // 조건절
    let param3 =
        " AND GRP_CD = '" + grp_cd + "'"
        + " AND CD = '01' "
        + " AND USE_YN = '1' "
        ;

    // 정렬    
    let param4 =
        " CD "
        ;

    // ds_test.DataId = 
    // "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=dinymicQueryTest" + "&param1=" + param1 
    //                                                                             + "&param2=" + param2
    //                                                                             + "&param3=" + param3 
    //                                                                             + "&param4=" + param4;	                                                    
    // ds_test.Reset();

    sbm_test.action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=dinymicQueryTest" + "&param1=" + param1 + "&param2=" + param2 + "&param3=" + param3 + "&param4=" + param4;
    $c.sbm.execute(sbm_test);
};

scwin.sbm_test_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code != 0) {
        return;
    }
    // console.log("  FI616 (조회데이터Row설정) 건수 ["+ds_test.getTotalRow()+"]");
};


//-------------------------------------------------------------------------
// FI624 (세무조사 아이디) 조회
//   증빙관리권한 : 세무조사시에만 사용하는 계정
//-------------------------------------------------------------------------
scwin.f_empNo = function () {
    console.log("===== f_empNo - FI624 (세무조사 아이디) 조회");

    let grp_cd = "FI624";  //세무조사 아이디
    let pCode = scwin.vUserId;

    // SELECT 절 
    let param1 =
        " CD      as COL1 "
        + ",CD_NM 	as COL2 "
        + ",'' 		as COL3 "
        + ",'' 		as COL4 "
        + ",'' 		as COL5 "
        + ",'' 		as COL6 "
        + ",''      as COL7 "
        + ",''      as COL8 "
        + ",''      as COL9 "
        + ",''      as COL10"
        ;

    // 대상테이블 	
    let param2 = " TB_ZZ002 ";

    // 조건절
    let param3 =
        " AND GRP_CD = '" + grp_cd + "'"
        + " AND USE_YN = '1' "
        //+ " AND CD_NM LIKE '"+pCode+"'% || '%'"
        + " AND CD_NM = '" + pCode + "' "
        ;

    let param4 = "CD";

    //ds_empNo.DataId = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=dinymicQueryTest" + "&param1=" + param1 + "&param2=" + param2 + "&param3=" + param3 + "&param4=" + param4;
    //ds_empNo.Reset();  

    sbm_empNo.action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=dinymicQueryTest" + "&param1=" + param1 + "&param2=" + param2 + "&param3=" + param3 + "&param4=" + param4;
    $c.sbm.execute(sbm_empNo);
};


scwin.sbm_empNo_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code != 0) {
        return;
    }

// language=JavaScript for=ds_empNo event=OnLoadCompleted(rowCnt)>

    if (ds_empNo.getRowCount() > 0) {

        //gr_total1.setColumnVisible(columnInfo, columnVisible);

        gr_total1.setColumnVisible("evidenceCnt", false);
        gr_total2.setColumnVisible("evidenceCnt", false);
        gr_total3.setColumnVisible("evidenceCnt", false);

        // 전자세금계산서
        gr_total1.setColumnVisible("eseroElecCnt", false);
        gr_total2.setColumnVisible("eseroElecCnt", false);
        gr_total3.setColumnVisible("eseroElecCnt", false);

        // 종이세금계산서
        gr_total1.setColumnVisible("paperTaxCnt", false);
        gr_total2.setColumnVisible("paperTaxCnt", false);
        gr_total3.setColumnVisible("paperTaxCnt", false);

        // 전자계산서
        gr_total1.setColumnVisible("eseroTaxCnt", false);
        gr_total2.setColumnVisible("eseroTaxCnt", false);
        gr_total3.setColumnVisible("eseroTaxCnt", false);

        // 종이계산서
        gr_total1.setColumnVisible("paperCnt", false);
        gr_total2.setColumnVisible("paperCnt", false);
        gr_total3.setColumnVisible("paperCnt", false);

        // 기타
        gr_total1.setColumnVisible("etcCnt", false);
        gr_total2.setColumnVisible("etcCnt", false);
        gr_total3.setColumnVisible("etcCnt", false);

        // 종이세금계산서(RPA)
        gr_total1.setColumnVisible("paperTaxRpaCnt", false);
        gr_total2.setColumnVisible("paperTaxRpaCnt", false);
        gr_total3.setColumnVisible("paperTaxRpaCnt", false);

        // 작성자
        gr_total1.setColumnVisible("drawEmpNm", false);
        gr_total2.setColumnVisible("drawEmpNm", false);
        gr_total3.setColumnVisible("drawEmpNm", false);

        ed_qryYm.setValue("201501");
        ed_qryYmEnd.setValue("201501");

        //ozprint.style.display = "none";

    } else {
        // 증빙 관련 컬럼 표시
        gr_total1.setColumnVisible("evidenceCnt", true);
        gr_total2.setColumnVisible("evidenceCnt", true);
        gr_total3.setColumnVisible("evidenceCnt", true);

        gr_total1.setColumnVisible("eseroElecCnt", true);
        gr_total2.setColumnVisible("eseroElecCnt", true);
        gr_total3.setColumnVisible("eseroElecCnt", true);

        gr_total1.setColumnVisible("paperTaxCnt", true);
        gr_total2.setColumnVisible("paperTaxCnt", true);
        gr_total3.setColumnVisible("paperTaxCnt", true);

        gr_total1.setColumnVisible("eseroTaxCnt", true);
        gr_total2.setColumnVisible("eseroTaxCnt", true);
        gr_total3.setColumnVisible("eseroTaxCnt", true);

        gr_total1.setColumnVisible("paperCnt", true);
        gr_total2.setColumnVisible("paperCnt", true);
        gr_total3.setColumnVisible("paperCnt", true);

        gr_total1.setColumnVisible("etcCnt", true);
        gr_total2.setColumnVisible("etcCnt", true);
        gr_total3.setColumnVisible("etcCnt", true);

        gr_total1.setColumnVisible("paperTaxRpaCnt", true);
        gr_total2.setColumnVisible("paperTaxRpaCnt", true);
        gr_total3.setColumnVisible("paperTaxRpaCnt", true);

        gr_total1.setColumnVisible("drawEmpNm", true);
        gr_total2.setColumnVisible("drawEmpNm", true);
        gr_total3.setColumnVisible("drawEmpNm", true);

        //ozprint.style.display = "block";
    }
};



// @@ ====== 조회 ============================================================================== //

//-------------------------------------------------------------------------
// 초기화 버튼 클릭
//-------------------------------------------------------------------------
scwin.f_SearchClear = function () {
    $c.gus.cfInitObjects(searchTable);
    scwin.f_Setting();
    //scwin.f_setCompanyInfo();
};


//-------------------------------------------------------------------------
// 조회(총계정원장)
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    console.log("====== f_Retrieve ==================");

    let ret;

    ret = await $c.gus.cfValidate([ed_coCd				// 회사코드
        , ed_qryYm			// 회계년월
        , ed_qryYmEnd		// 회계년월
        , ed_acctCdSt			// 계정  		                    
    ]);

    if (!ret)
        return false;

    if (!scwin.f_HiddenCheck(ed_acctCdSt, "계정")) return false;

    if (!scwin.f_HiddenCheck(ed_acctDeptCd, "귀속부서")) return false;

    if (!scwin.f_BetweenCheck(ed_qryYm.getValue().trim(), ed_qryYmEnd.getValue().trim())) {
        await $c.gus.cfAlertMsg($c.data.getMessage(MSG_CM_ERR_057, "회계년월To", "회계년월From"));
        //lc_postYn

        // if (lc_postYn.getValue() == '1') {
        //     $c.gus.cfAlertMsg(MSG_CM_ERR_057, Array("회계년월To", "회계년월From"));
        // } else if (lc_postYn.getValue() == '0') {
        //     $c.gus.cfAlertMsg(MSG_CM_ERR_057, Array("작성년월To", "작성년월From"));
        // }
        ed_acctCdSt.focus();
        return false;
    }

    // 세무조사 관련 일자 제한	
    if (ds_empNo.getRowCount() > 0) {
        if (ed_qryYm.getValue() != "" && ed_qryYmEnd.getValue() != "") {
            if (ed_qryYm.getValue().substr(0, 4) <= "2013" || ed_qryYmEnd.getValue().substr(0, 4) >= "2019") {
                await $c.win.alert("2014~2018년 이외의 조회 권한이 없습니다.");
                return;
            }
        }
    }

	    // var qryYm = ed_qryYm.Text+"01";
	    // var qryYmEnd = ed_qryYmEnd.Text+"01";
	    // var diffObj = cfDifferBetween(qryYm, qryYmEnd);	    
	    // var monthGap = diffObj.year * 12 + diffObj.month;  // 년도차이와 월차이를 합해서 차이를 월로만 표시(1년1개월 => 13개월)  

    var qryYm = ed_qryYm.getValue()+"01";
    var qryYmEnd = ed_qryYmEnd.getValue()+"01";
    var diffObj = await $c.gus.cfDifferBetween(qryYm, qryYmEnd, "YYYYMMDD");
    var monthGap = diffObj.year * 12 + diffObj.month;  // 년도차이와 월차이를 합해서 차이를 월로만 표시(1년1개월 => 13개월)  

    console.log(" qryYm ["+qryYm+"]  qryYmEnd ["+qryYmEnd+"]  year ["+JSON.stringify(diffObj.year)+"] month ["+JSON.stringify(diffObj.month)+"]   monthGap ["+monthGap+"]");

    // 1년이상 조회금지
    if ((monthGap > 11)) {
        await $c.win.alert("기간을 1년이상 조회하실수 없습니다.");
        return false;
    }

    //ds_search.UseChangeInfo = false;

    ///////////////////////////////////////////
    // 속도개선을 위한 추가조회(2013.03.20 이석건) 
    if (ds_test.getRowCount() > 0) {
        scwin.quantityOfRows = ds_test.getCellData(0, 'col2');
    }

    scwin.txt_pageNumber = scwin.pageNumber;
    scwin.txt_quantityOfRows = scwin.quantityOfRows;

    // if (lc_qryCond.BindColVal == "1"){
    //        gr_total1.ReDraw = "false";
    // }else if(lc_qryCond.BindColVal == "2"){
    //         gr_total2.ReDraw = "false";
    // }else if(lc_qryCond.BindColVal == "3"){
    //         gr_total3.ReDraw = "false";
    // }

    ///////////////////////////////////////////

    if (bSearch2._getVisible() == false) {
        bSearch2.show();
    }

    // var strParam = "?qryYm="              	+ ed_qryYm.Text                	// 회계년월
    //                 + "&qryYmEnd="            	+ ed_qryYmEnd.Text       		// 회계년월
    //                 + "&acctCdSt="         	+ ed_acctCdSt.Text           	// 계정
    //                 + "&acctDeptCd="          	+ ed_acctDeptCd.Text            // 부서코드
    //                 + "&crn="					+ ed_crn.Text					// 사업자번호
    //                 + "&qryCond="         		+ lc_qryCond.BindColVal         // 조회조건
    //                 + "&clntNo="          		+ ed_clntNo.Text            	// 거래처코드
    //                 + "&coCd="         		+ ed_coCd.Text           		// 회사코드
    //                 + "&coClsCd="             	+ txtCoClsCd.value              // 자회사구분
    //                 + "&postYn="            	+ lc_postYn.BindColVal          // 가결구분
    //                 + "&pageNumber="        	+ txt_pageNumber.value        	// page번호
    //                 + "&quantityOfRows="		+ txt_quantityOfRows.value		// 열의 갯수
    //                 + "&lowerDeptIncluYn="		+ chk_lowerDeptIncluYn.checked	// 하위부서여부
    //                 + "&bizDomCd="				+ ed_BizDomCd.Text				// 사업영역	                 
    //                 ;

    ds_search.set("qryYm", ed_qryYm.getValue());
    ds_search.set("qryYmEnd", ed_qryYmEnd.getValue());
    ds_search.set("acctCdSt", ed_acctCdSt.getValue());
    ds_search.set("acctDeptCd", ed_acctDeptCd.getValue());
    ds_search.set("crn", ed_crn.getValue());
    ds_search.set("qryCond", lc_qryCond.getValue());
    ds_search.set("clntNo", ed_clntNo.getValue());
    ds_search.set("coCd", ed_coCd.getValue());
    ds_search.set("coClsCd", scwin.txtCoClsCd);
    ds_search.set("postYn", lc_postYn.getValue());
    ds_search.set("pageNumber", scwin.txt_pageNumber);
    ds_search.set("quantityOfRows", scwin.txt_quantityOfRows);
    ds_search.set("lowerDeptIncluYn", cbx_lowerDeptIncluYn.getValue());
    ds_search.set("bizDomCd", ed_BizDomCd.getValue());

    var dc = ds_search.getJSON();
    console.log("  *** ds_search : "+ JSON.stringify(dc));

    //ds_total.DataID = "/ac.fi.gnrlaccount.ledgmgnt.RetrieveTotalAccountLedgerCMD.do" + strParam; 
    //ds_total.Reset(); 
    $c.sbm.execute(sbm_retrieve);
};

//-------------------------------------------------------------------------
// 조회(총계정원장) submitdone
//-------------------------------------------------------------------------
scwin.sbm_retrieve_submitdone = function (e) {

    if (e.responseJSON.resultDataSet[0].Code != 0) {
        return;
    }

// language=JavaScript for=ds_total event=OnLoadCompleted(rowCnt)>

    if (lc_qryCond.getValue() == "1") {
        //cfHideDSWaitMsg(gr_total1);
    } else if (lc_qryCond.getValue() == "2") {
        //cfHideDSWaitMsg(gr_total2);
    } else if (lc_qryCond.getValue() == "3") {
        //cfHideDSWaitMsg(gr_total3);
    }

    let temp = ds_total.getRowCount();
    ed_totalRows.setValue(temp);
    ed_totalRows2.setValue(temp);
    ed_totalRows3.setValue(temp);
    //cfShowTotalRows(totalRows, temp);
    if (temp == 0) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        //속도개선을 위한 추가조회(2013.03.20 이석건)
        $c.gus.cfDisableObjects([btn_addSearch]);
        bSearch2.hide();
        console.log('set nm2');
        for (var idx = 0; idx < ds_total.getRowCount(); idx++) {
            var tmpAcctDeptNm = ds_total.getCellData(idx, 'acctDeptNm');
            ds_total.setCellData(idx, 'acctDeptNm2', tmpAcctDeptNm);
        }
        scwin.sorting();
    }
    else {
        //조회 완료후 추가조회
        bSearch2.hide();
        scwin.f_Retrieve2();
    }
    $c.gus.cfEnableObjects([btn_addSearch]);

    if (lc_qryCond.BindColVal == "1") {
        //gr_total1.ReDraw = "true";
    } else if (lc_qryCond.BindColVal == "2") {
        //gr_total2.ReDraw = "true";
    } else if (lc_qryCond.BindColVal == "3") {
        //gr_total3.ReDraw = "true";
    }
};


//-------------------------------------------------------------------------
// 속도개선을 위한 추가조회 (총계정원장)
//-------------------------------------------------------------------------
scwin.f_Retrieve2 = function () {

    let pagenum = parseInt(scwin.txt_pageNumber) + 1;
    let quantityOfRows2 = parseInt(scwin.txt_quantityOfRows);

    scwin.txt_pageNumber = pagenum;
    scwin.txt_quantityOfRows = quantityOfRows2;

    if (bSearch._getVisible() == false) {
        bSearch.show();
    }

    ds_search.set("qryYm", ed_qryYm.getValue());    // 회계년월
    ds_search.set("qryYmEnd", ed_qryYmEnd.getValue());
    ds_search.set("acctCdSt", ed_acctCdSt.getValue());
    ds_search.set("acctDeptCd", ed_acctDeptCd.getValue());
    ds_search.set("crn", ed_crn.getValue());
    ds_search.set("qryCond", lc_qryCond.getValue());
    ds_search.set("clntNo", ed_clntNo.getValue());
    ds_search.set("coCd", ed_coCd.getValue());
    ds_search.set("coClsCd", scwin.txtCoClsCd);
    ds_search.set("postYn", lc_postYn.getValue());
    ds_search.set("pageNumber", scwin.txt_pageNumber);
    ds_search.set("quantityOfRows", scwin.txt_quantityOfRows);
    ds_search.set("lowerDeptIncluYn", cbx_lowerDeptIncluYn.getValue());
    ds_search.set("bizDomCd", ed_BizDomCd.getValue());

    // var strParam = "?qryYm="              	+ ed_qryYm.Text                	// 회계년월
    //                 + "&qryYmEnd="            	+ ed_qryYmEnd.Text       		// 회계년월
    //                 + "&acctCdSt="         	+ ed_acctCdSt.Text           	// 계정
    //                 + "&acctDeptCd="          	+ ed_acctDeptCd.Text            // 부서코드
    //                 + "&crn="					+ ed_crn.Text					// 사업자번호
    //                 + "&qryCond="         		+ lc_qryCond.BindColVal         // 조회조건
    //                 + "&clntNo="          		+ ed_clntNo.Text            	// 거래처코드
    //                 + "&coCd="         		+ ed_coCd.Text           		// 회사코드
