//-------------------------------------------------------------------------
// 속도개선을 위한 추가조회 (총계정원장) submitdone
//-------------------------------------------------------------------------
scwin.sbm_retrieve2_submitdone = function (e) {

    if (e.responseJSON.resultDataSet[0].Code != 0) {
        return;
    }

// <!-- 속도개선을 위한 추가조회(2013.03.20 이석건) -->
// language=JavaScript for=ds_total2 event=OnLoadCompleted(rowCnt)>

    lAddRow.show();
    let rowCnt = ds_total2.getRowCount();
    if (rowCnt > 0) {
        //ds_total.ImportData(ds_total2.ExportData(1, ds_total2.getRowCount(), false));
        ds_total.setJSON(ds_total2.getAllJSON(), true);
        ds_total.modifyAllStatus("R");
    }
    lAddRow.hide();

    //cfShowTotalRows(totalRows, ds_total.CountRow);  
    ed_totalRows.setValue(ds_total.getRowCount())
    ed_totalRows2.setValue(ds_total.getRowCount())
    ed_totalRows3.setValue(ds_total.getRowCount())

    ds_total2.removeAll();

    if (rowCnt == 0) {
        $c.gus.cfDisableObjects([btn_addSearch]);
        bSearch.hide();
        console.log('set nm2');
        for (var idx = 0; idx < ds_total.getRowCount(); idx++) {
            var tmpAcctDeptNm = ds_total.getCellData(idx, 'acctDeptNm');
            ds_total.setCellData(idx, 'acctDeptNm2', tmpAcctDeptNm);
        }
        scwin.sorting();
    }
    else {
        //recursive 조회
        scwin.f_Retrieve2();
        bSearch.show();
        $c.gus.cfDisableObjects([btn_addSearch]);
    }
};




