//-------------------------------------------------------------------------
// f_openPopUp 팝업  @@
//   1:계정,3:부서,4:거래처,8:사업자
//-------------------------------------------------------------------------
scwin.f_openPopUp = function (flag, check) {
    console.log("=== f_openPopUp ( flag[ " + flag + " ]  check[ " + check + " ]   1:계정,3:부서,4:거래처,8:사업자)");

    let qryYear = ed_qryYmEnd.getValue().trim().substring(0, 4);
    let temp = "";

    switch (flag) {
        case '1':
            // 계정조회 - 코드 널, 돋보기이면 전체 조회
            temp = ",,";
            console.log("  계정 popup  temp [" + temp + "]");

            // rtnList = cfCommonPopUp('retrieveAcctCdInfo',ed_acctCdSt.text.trim(),txt_acctCdStNm.value,check,null,null,null,null,temp,null,null,null,null);
            udc_acctCdSt.setSelectId("retrieveAcctCdInfo");
            udc_acctCdSt.cfCommonPopUp(scwin.udc_acctCdSt_cb, ed_acctCdSt.getValue().trim(), ed_acctCdStNm.getValue(), check, null, null, null, null, temp, null, null, null, null);

            break;

        case '3':
            // 회계부서
            temp = "," + ed_coCd.getValue() + "," + scwin.txtCoClsCd + ",0";
            console.log("  회계부서 popup  temp [" + temp + "]");

            // rtnList = cfCommonPopUp('retrieveAcctDeptCdInfo10',ed_acctDeptCd.text.trim(),txt_acctDeptNm.value,check,null,null,null,null,param,null,null,null,null,null,null,null,null,null,qryYear);
            udc_acctDeptCd.setSelectId("retrieveAcctDeptCdInfo10");
            udc_acctDeptCd.cfCommonPopUp(scwin.udc_acctDeptCd_cb,ed_acctDeptCd.getValue().trim(),ed_acctDeptNm.getValue(),check,null,null,null,null,temp,null,null,null,null,null,null,null,null,null,null,null,null,null,qryYear);

            break;

        case '4':
            // 거래처
            temp = ",,," + ed_coCd.getValue();
            console.log("  거래처 popup  temp [" + temp + "]");

            // rtnList = cfCommonPopUp('retrieveClntList2',ed_clntNo.text.trim(),txt_clntNm.value,check,null,null,null,null,param,null,null,null,null);
            udc_clntNo.setSelectId("retrieveClntList2");
            udc_clntNo.cfCommonPopUp(scwin.udc_clntNo_cb, ed_clntNo.getValue().trim(), ed_clntNm.getValue(), check, null, null, null, null, temp, null, null, null, null);
            break;

        case '8':
            // 사업자번호
            temp = "";
            console.log("  사업자번호 popup  temp [" + temp + "]");

            // rtnList = cfCommonPopUp(selectID,ed_crn.text.trim(),txt_crnNm.value,check,null,null,null,null,param,null,null,null,null);
            udc_crn.setSelectId("retrieveCrnInfo");
            udc_crn.cfCommonPopUp(scwin.udc_crn_cb, ed_crn.getValue().trim(), ed_busiNm.getValue(), check, null, null, null, null, temp, null, null, null, null);

            break;

        default:
            break;
    }
};

