scwin.f_PopUp2 = function (flag, check) {
    console.log("=== f_PopUp2 ( flag[ " + flag + " ]  check[ " + check + " ]   1:사업영역,2:사업자,3:귀속부서)");

	// var codeObj = paramArray.pCode;
	// var nameObj = paramArray.pName;

	// rtnList = cfCommonPopUp(paramArray.pSelectID, cfGetValue(codeObj), ""
	// 					   ,f_EventCheck(), paramArray.pDispCnt
	// 					   ,paramArray.pTitle, paramArray.pWidth
	// 					   ,paramArray.pHidden, paramArray.pWhere
	// 					   ,paramArray.pW, paramArray.pH
	// 					   ,paramArray.pTop, paramArray.pLeft
	// 					   ,paramArray.pExistTF, paramArray.pAllSearchTF
	// 					   ,paramArray.pWtitleSearch)
	// if (rtnList != null ) {
    // 	if (rtnList[0] != "N/A") {
    // 		cfSetValue(codeObj,rtnList[0]);
	// 		codeObj.hidVal = rtnList[0];
	// 		cfSetValue(nameObj,rtnList[1]);
	// 	}
    // } else {
	// 	cfSetValue(codeObj,"");
	// 	codeObj.hidVal = "";
	// 	cfSetValue(nameObj,"");
    // }
	// return rtnList;

    let temp = ""; // where 절

    switch (flag) {
        case '1':
            // 사업영역 (널이면 전체조회)
            udc_BizDomCd.setSelectId("retrieveBizDomCdInfo");
            udc_BizDomCd.cfCommonPopUp(scwin.udc_BizDomCd_cb, ed_BizDomCd.getValue().trim(), ed_BizDomNm.getValue(), check, null, null, null, null, temp, null, null, null, null);
            break;

        case '2':
            // 사업자번호
            udc_crn.setSelectId("retrieveCrnInfo");
            udc_crn.cfCommonPopUp(scwin.udc_crn_cb, ed_crn.getValue().trim(), ed_busiNm.getValue(), check, null, null, null, null, temp, null, null, null, null);
            break;

        case '3':
            // 귀속부서 (널이면 전체조회)
            temp = scwin.today;

            if (scwin.vCoClsCd > ACConstants.CO_CLS_CD_DONGBU) {  	// 자회사 회계 시스템
                temp = temp + "," + scwin.vCoCd + "," + scwin.vCoClsCd;
            }

            console.log("  귀속부서 popup2  temp [" + temp + "]");

            udc_acctDeptCd.setSelectId("retrieveAcctDeptCdInfo6");
            udc_acctDeptCd.cfCommonPopUp(scwin.udc_acctDeptCd_cb, ed_acctDeptCd.getValue().trim(), ed_acctDeptNm.getValue(), check, null, null, null, null, temp, null, null, null, null);
            break;

        default:
            break;
    }
};


// @@ ====== 팝업 callBackFunc ================================================================= //
//   1:사업영역,2:사업자번호,3:귀속부서

//-------------------------------------------------------------------------
// 회사 입력 팝업 callBack
//-------------------------------------------------------------------------
scwin.udc_coCd_cb = function (rtnList) {
    // SET	 
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;

        if (ed_coCd.options.hidVal != rtnList[0])
            scwin.f_initObj();

        ed_coCd.setValue(rtnList[0]);	// 코드
        ed_coNm.setValue(rtnList[5]); // 회사명 
        ed_coCd.options.hidVal = rtnList[0];  // 히든값
        scwin.txtCoClsCd = rtnList[1];	// 회사구분    

    } else {
        ed_coCd.setValue("");
        ed_coNm.setValue("");
        ed_coCd.options.hidVal = "";
        scwin.txtCoClsCd = "";
    }

    if (scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU) {  	// 자회사 회계 시스템 
        scwin.isSubCompany = true;
    } else {
        scwin.isSubCompany = false;
    }

    if (scwin.load) {
        if ('T' == scwin.privAdmin || !scwin.isSubCompany) { // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
            $c.gus.cfEnableObjects([ed_coCd, ed_coNm, btn_company]);
        } else {
            $c.gus.cfDisableObjects([ed_coCd, ed_coNm, btn_company]);
        }

        scwin.load = false;
    }
};

scwin.f_initObj = function () {
    $c.gus.cfInitObjects([ed_acctDeptCd, ed_acctDeptNm]); // 부서코드 
    $c.gus.cfInitObjects([ed_clntNo, ed_clntNm]); //  거래처 코드 
}

