//-------------------------------------------------------------------------
// 팝업결과  @@
//-------------------------------------------------------------------------
scwin.f_resultPopEd = function (strCd, strNm, rtnList) {
    console.log("=== f_resultPopEd (팝업결과)   rtnList ["+rtnList+"]");

    if (rtnList != null) {
        if (rtnList[0] == "N/A") {  // 팝업 그냥 닫음
            strCd.setValue("");
            strNm.setValue("");
            strCd.options.hidVal = "";
            strNm.options.hidVal = "";
            return;
        }
        strCd.setValue(rtnList[0]);	// 코드
        strNm.setValue(rtnList[1]);	// 명
        strCd.options.hidVal = rtnList[0];  // 히든값
        strNm.options.hidVal = rtnList[1]
    } else {
        strCd.setValue("");
        strNm.setValue("");
        strCd.options.hidVal = "";
        strNm.options.hidVal = "";
    }
};

//-------------------------------------------------------------------------
// 팝업체크  @@
//-------------------------------------------------------------------------
scwin.f_checkPopEd = function (strCd, strNm, flag) {
    var val = strCd.options.hidVal;
    console.log("===== f_checkPopEd (팝업체크 - 코드값 변경시 자동검색  srtCd["+strCd.getValue()+"] strNm["+strNm.getValue()+"] hidVal["+val+"] flag["+flag+"]");

    if (strCd.getValue().trim() == strCd.options.hidVal) {
        // KYU_TEST : 히든 비교시 코드가 null 이 아니어야 함. (코드 null 일 때 명 null 처리)
        if (strCd.getValue() != "") return;
    }

    strNm.setValue("");
    strCd.options.hidVal = "";
    if (strCd.getValue().trim() != "") scwin.f_openPopUp(flag, 'T');
};


