//가결구분 변경시 문구 변경
scwin.lc_postYn_onchange = function (info) {
    if (info.newValue == '1') {
        txt_qryYm.setValue('회계연월');
    } else if (info.newValue == '0') {
        txt_qryYm.setValue('작성연월');
    }
};

//-------------------------------------------------------------------------
// 조회조건 변경
//-------------------------------------------------------------------------
scwin.lc_qryCond_onchange = function (info) {
    scwin.f_QryCond();
    scwin.sorting();
};

//-------------------------------------------------------------------------
//  조건이 바뀔때마다(1^계정,2^부서,3^거래처)
//------------------------------------------------------------------------- 
scwin.f_QryCond = function () {
    if (lc_qryCond.getValue() == "1") {
        btn_com1.show();
        btn_com2.hide();
        btn_com3.hide();
        gr1.show();
        gr2.hide();
        gr3.hide();
        //ds_total.SubsumExpr = "2:acctCd,1:subSumPostDt";
        //ds_total.SortExpr = "+acctCd+postDt+acctDeptNm+crn";
    } else if (lc_qryCond.getValue() == "2") {
        gr1.hide();
        gr2.show();
        gr3.hide();
        btn_com1.hide();
        btn_com2.show();
        btn_com3.hide();
        //ds_total.SubsumExpr = "2:acctDeptCd,1:acctDeptCd:acctCd";
        //ds_total.SortExpr = "+acctDeptCd +acctCd +postDt+slipNo+crn";
    } else if (lc_qryCond.getValue() == "3") {
        gr1.hide();
        gr2.hide();
        gr3.show();
        btn_com1.hide();
        btn_com2.hide();
        btn_com3.show();
        //ds_total.SubsumExpr = "2:mgntClntNo,1:mgntClntNo:acctCd";
        //ds_total.SortExpr = "+mgntClntNo +acctCd +postDt+slipNo+crn";
    }
    //ds_total.Sort();
    ds_total.setRowPosition(0);
};

scwin.sorting = function () {
    var options = {};
    ds_total.clearSort();
    if (lc_qryCond.getValue() == "1") {
        options.sortOrder = "1 1 1 1";
        options.sortIndex = "acctCd postDt acctDeptNm crn";
    } else if (lc_qryCond.getValue() == "2") {
        options.sortOrder = "1 1 1 1 1";
        options.sortIndex = "acctDeptCd acctCd postDt slipNo crn";
    } else if (lc_qryCond.getValue() == "3") {
        options.sortOrder = "1 1 1 1 1";
        options.sortIndex = "mgntClntNo acctCd postDt slipNo crn";
    }
    ds_total.multisort(options);
};


//소계컬럼에 targetColumnID 값 세팅
scwin.subtotalTargetColumnView = function (rowIndex, tci) {
    return ds_total.getCellData(rowIndex, tci);
};


scwin.ds_total2_ondataload = function () {
// language=JavaScript for=ds_total2 event=OnLoadProcess(rowCnt)>
    let rowCnt = ds_total2.getRowCount();
    if (rowCnt > 0) {
        // 병합중 메세지 
        lAddRow.show();
        // 조회 메시지
        bSearch.hide();
    }
};


