//-------------------------------------------------------------------------
// 엑셀 파일 다운로드
//-------------------------------------------------------------------------
scwin.f_Excel = async function () {
    console.log('------------------------------------');
    let objGridName, ret;

    if (lc_qryCond.getValue() == "1") {
        objGridName = gr_total1;
    } else if (lc_qryCond.getValue() == "2") {
        objGridName = gr_total2;
    } else if (lc_qryCond.getValue() == "3") {
        objGridName = gr_total3;
    }

    ret = await $c.win.confirm("Excel로 다운로드 하시겠습니까?");
    if (ret) {
        //cfGridToExcel(objGridName, "총계정원장집계표","총계정원장집계표.xls",8+16);

        let sheetTitle = "총계정원장조회";
        let gridId = objGridName;
        let infoArr = [];
        let options = {
            fileName: sheetTitle + ".xlsx",    // + ".xls",
            sheetName: sheetTitle
            // fileName : "총계정원장집계표(외화).xls" //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
        };
        $c.data.downloadGridViewExcel(gridId, options, infoArr);
    }
};
